  const role=()=>S(user().role||user().user_role||user().type);
  const isWarehouseOnly=()=>role()==='warehouse_manager';
  const isAdmin=()=>{const u=user(); const txt=[u.role,u.user_role,u.type,u.position,u.username,u.full_name,u.name,u.email].map(S).join(' ').toLowerCase(); return /admin|system|manager|owner|مدير|النظام|ادارة|الإدارة/.test(txt) || role()==='general_manager' || role()==='system_admin';};
  const itemCode=i=>S(i&&(i.product_code||i.serial_number||i.barcode||i.supplier_barcode||i.code));
