  function oneRow(res,label){ if(res&&res.error) throw res.error; const d=res?res.data:null; if(Array.isArray(d)){ if(!d.length) throw new Error((label||'العملية')+' لم ترجع بيانات'); return d[0]; } if(!d) throw new Error((label||'العملية')+' لم ترجع بيانات'); return d; }
  window.oneRow=window.__tasneefOneRow=oneRow;
  function safeJson(v){ const t=S(v); if(!t.startsWith('finance_pro_v15:')) return null; try{return JSON.parse(t.replace('finance_pro_v15:',''))||{};}catch(_){return{};} }
