  function supplierList(){const set=new Set(); A(state.suppliers).forEach(s=>S(s)&&set.add(S(s))); A(state.items).forEach(i=>S(i.supplier)&&set.add(S(i.supplier))); A(state.movements).forEach(m=>S(m.movement_type)==='in'&&S(m.receiver)&&set.add(S(m.receiver))); A(state.expenses).forEach(e=>S(e.supplier)&&set.add(S(e.supplier))); return [...set].filter(Boolean).sort((a,b)=>a.localeCompare(b,'ar'));}
  function financeTabs(){const all=[['summary','ملخص'],['products','منتجات'],['suppliers','الموردين'],['add','العمليات'],['movement','حركة المخزون'],['cost','مركز تكلفة'],['reports','تقارير']]; return isWarehouseOnly()?all.filter(t=>['products','movement','reports'].includes(t[0])):all;}
  function ensureAllowedTab(){const ids=financeTabs().map(t=>t[0]); if(!ids.includes(state.tab))state.tab=ids[0]||'products';}
  function ensureStyle(){ if($('financeInventoryProStyleV10088'))return; const st=document.createElement('style'); st.id='financeInventoryProStyleV10088'; st.textContent=`#financeDashboard.finance-pro{display:block}.fin-shell{display:grid;gap:14px}.fin-hero{background:linear-gradient(135deg,#073d31,#11634d);color:#fff;border-radius:22px;padding:20px 22px;display:flex;justify-content:space-between;gap:14px;align-items:center;box-shadow:0 16px 40px rgba(10,64,51,.14)}.fin-hero h2{margin:0;color:#fff;font-size:28px}.fin-hero p{margin:6px 0 0;color:#dff4ee}.fin-tabs{display:grid;grid-template-columns:repeat(7,1fr);gap:8px}.fin-tabs button{background:#eef7f3;color:#073d31;border:1px solid #cfe3db;border-radius:14px;padding:12px}.fin-tabs button.active{background:#073d31;color:#fff}.fin-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.fin-grid.three{grid-template-columns:repeat(3,1fr)}.fin-grid.two{grid-template-columns:repeat(2,1fr)}.fin-card{background:#fff;border:1px solid #d9e7e2;border-radius:18px;padding:16px;box-shadow:0 8px 24px rgba(10,64,51,.05)}.fin-card h3{margin:0 0 12px;color:#073d31}.fin-kpi small{color:#667c75}.fin-kpi b{display:block;margin-top:8px;color:#073d31;font-size:26px}.fin-actions{display:flex;gap:8px;align-items:end;flex-wrap:wrap}.fin-actions>*{min-width:130px}.fin-soft{background:#f4faf7;border:1px solid #d8ebe3;border-radius:14px;padding:12px}.fin-table{overflow:auto;border:1px solid #d9e7e2;border-radius:15px;background:#fff;max-height:58vh}.fin-table table{width:100%;border-collapse:collapse;font-size:13px}.fin-table th,.fin-table td{padding:10px;border-bottom:1px solid #edf2f0;text-align:right;white-space:nowrap}.fin-table th{position:sticky;top:0;background:#f8fbfa;color:#46645b;z-index:1}.fin-badge{display:inline-flex;border-radius:999px;padding:5px 10px;font-weight:800;font-size:12px;background:#e8f4ee;color:#087047}.fin-badge.warn{background:#fff4d9;color:#8a5b00}.fin-badge.bad{background:#fde8e8;color:#a92525}.fin-line{display:grid;grid-template-columns:1.2fr 1fr .7fr .8fr .8fr auto;gap:8px;align-items:end;margin-bottom:8px}.fin-line.dist{grid-template-columns:.8fr 1fr 1fr .7fr 1.2fr auto}.fin-report-cards{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px}.fin-product-card{border:1px solid #d9e7e2;border-radius:16px;padding:14px;background:linear-gradient(180deg,#fff,#f8fbfa)}.fin-product-card h4{margin:0 0 7px;color:#073d31}.fin-meta{display:grid;grid-template-columns:1fr 1fr;gap:7px;margin-top:10px}.fin-meta div{background:#f0f7f4;border:1px solid #ddebe6;border-radius:12px;padding:8px}.fin-meta small{display:block;color:#687b75}.fin-meta b{color:#073d31}.fin-thumb{width:74px;height:74px;border-radius:14px;border:1px solid #d9e7e2;background:#fff;object-fit:contain;padding:3px;float:left;margin-inline-start:10px}.fin-card-actions{display:flex;gap:8px;flex-wrap:wrap;margin-top:12px}.fin-card-actions button{padding:8px 11px;border-radius:11px}@media(max-width:1100px){.fin-tabs,.fin-grid,.fin-grid.three,.fin-grid.two{grid-template-columns:1fr 1fr}.fin-line,.fin-line.dist{grid-template-columns:1fr}.fin-hero{flex-direction:column;align-items:flex-start}}@media(max-width:700px){.fin-tabs,.fin-grid,.fin-grid.three,.fin-grid.two{grid-template-columns:1fr}}`; document.head.appendChild(st); }
  function ensurePage(){ ensureStyle(); let page=$('financeDashboard'); if(page){page.className='page hidden finance-pro';return page;} page=document.createElement('section'); page.id='financeDashboard'; page.className='page hidden finance-pro'; (document.querySelector('main.content')||document.querySelector('.content')||document.body).appendChild(page); return page; }
  async function loadAll(force){ if(state.loaded&&!force)return; const [items,movements,expenses,projects,users,tickets]=await Promise.all([table('inventory_items','*',5000),table('inventory_movements','*',5000),table('finance_expenses','*',5000),table('projects','*',5000),table('app_users','*',2000),table('tickets','*',3000)]); Object.assign(state,{items,movements,expenses,projects,users,tickets,suppliers:[...new Set([...localSuppliers(),...supplierList()])].filter(Boolean).sort((a,b)=>a.localeCompare(b,'ar')),loaded:true}); }
