  function renderBody(){const body=$('finBodyV15'); if(!body)return; if(!state.loaded){body.innerHTML='<div class="fin-card">جاري تحميل البيانات...</div>'; return;} ({summary:renderSummary,products:renderProducts,suppliers:renderSuppliers,add:renderAddStock,movement:renderMovement,cost:renderCostCenter,reports:renderReports}[state.tab]||renderSummary)(body);}
  function renderSummary(body){const stock=stockValue(), fin=movementsFinancial(); body.innerHTML=`<div class="fin-grid"><div class="fin-card fin-kpi"><small>عدد المنتجات</small><b>${state.items.length}</b></div><div class="fin-card fin-kpi"><small>السعر قبل الضريبة</small><b>${money(stock)}</b></div><div class="fin-card fin-kpi"><small>الضريبة</small><b>${money(stock*VAT)}</b></div><div class="fin-card fin-kpi"><small>السعر شامل الضريبة</small><b>${money(stock*(1+VAT))}</b></div></div><div class="fin-card"><h3>الأصناف التي سوف تنتهي (${lowItems().length})</h3><div class="fin-table"><table><thead><tr><th>المنتج</th><th>الكود</th><th>المتوفر</th><th>الحد الأدنى</th><th>التكلفة</th><th>الحالة</th></tr></thead><tbody>${lowItems().map(i=>`<tr><td><b>${esc(i.name)}</b></td><td>${esc(itemCode(i)||'-')}</td><td>${N(computedItemQty(i))}</td><td>${N(i.min_quantity||1)}</td><td>${money(itemUnitCost(i))}</td><td><span class="fin-badge warn">قارب الانتهاء</span></td></tr>`).join('')||'<tr><td colspan="6">لا توجد أصناف قاربت الانتهاء</td></tr>'}</tbody></table></div></div><div class="fin-grid three"><div class="fin-card fin-kpi"><small>حركة المخزون قبل الضريبة</small><b>${money(fin.net)}</b></div><div class="fin-card fin-kpi"><small>ضريبة حركة المخزون</small><b>${money(fin.vat)}</b></div><div class="fin-card fin-kpi"><small>حركة المخزون بعد الضريبة</small><b>${money(fin.gross)}</b></div></div>`;}
