  window.financeProDeleteSupplierV15=async function(name){try{const supplier=S(name); if(!supplier)return; if(!confirm('حذف اسم المورد من النظام؟ لن يتم حذف المنتجات أو الحركات، سيتم إزالة اسم المورد حتى يختفي مباشرة.'))return; state.suppliers=state.suppliers.filter(s=>S(s)!==supplier); saveLocalSuppliers(state.suppliers); state.items.forEach(i=>{if(S(i.supplier)===supplier)i.supplier='';}); state.expenses.forEach(e=>{if(S(e.supplier)===supplier)e.supplier='';}); renderSuppliersList(); const c=client(); if(c){const a=await c.from('inventory_items').update({supplier:''}).eq('supplier',supplier); if(a.error)throw a.error; const b=await c.from('finance_expenses').update({supplier:''}).eq('supplier',supplier); if(b.error)console.warn(b.error);} await loadAll(true); renderBody(); if(typeof msg==='function')msg('تم حذف المورد من الواجهة والسيرفر');}catch(e){alert(e.message||String(e));}};
  function invoicesFromMovements(){const map=new Map(); state.movements.filter(m=>S(m.movement_type)==='in').forEach(m=>{const meta=safeJson(m.notes)||{}; const invoiceNo=S(meta.invoiceNo)||((S(m.reason).match(/فاتورة\s+(.+)$/)||[])[1])||'بدون رقم'; if(!map.has(invoiceNo))map.set(invoiceNo,{invoiceNo,supplier:S(meta.supplier||m.receiver||''),date:S(m.movement_date||m.created_at).slice(0,10),lines:[],net:0,vat:0,gross:0}); const inv=map.get(invoiceNo); inv.lines.push(m); inv.net+=movementNet(m); inv.vat+=movementVat(m); inv.gross+=movementGross(m); if(!inv.supplier)inv.supplier=S(m.receiver||'');}); return[...map.values()].sort((a,b)=>S(b.date).localeCompare(S(a.date)));}
  function renderInvoicesList(){const box=$('finInvoicesListV15'); if(!box)return; const rows=invoicesFromMovements(); box.innerHTML=`<div class="fin-card"><h3>الفواتير المسجلة</h3><div class="fin-table"><table><thead><tr><th>رقم الفاتورة</th><th>المورد</th><th>التاريخ</th><th>عدد المنتجات</th><th>قبل الضريبة</th><th>بعد الضريبة</th><th>إجراء</th></tr></thead><tbody>${rows.map(inv=>`<tr><td><b>${esc(inv.invoiceNo)}</b></td><td>${esc(inv.supplier||'-')}</td><td>${esc(inv.date||'-')}</td><td>${inv.lines.length}</td><td>${money(inv.net)}</td><td>${money(inv.gross||inv.net)}</td><td class="fin-actions"><button class="light" onclick="financeProShowInvoiceV15('${encodeURIComponent(inv.invoiceNo)}')">عرض</button><button onclick="financeProLoadSupplierInvoiceV15('${encodeURIComponent(inv.invoiceNo)}')">تحميل العملية</button>${isAdmin()?`<button class="danger" onclick="financeProDeleteSupplierInvoiceV15('${encodeURIComponent(inv.invoiceNo)}',this)">حذف الفاتورة</button>`:''}</td></tr>`).join('')||'<tr><td colspan="7">لا توجد فواتير</td></tr>'}</tbody></table></div></div>`;}
