  window.financeProAddInvoiceLineV15=function(){const existingId=S($('finExistingProductV15')?.value); const line={existing_item_id:existingId,name:S($('finLineNameV15')?.value),code:S($('finLineCodeV15')?.value),distributor_code:S($('finLineDistributorCodeV15')?.value),supplier_invoice_no:S($('finLineSupplierInvoiceV15')?.value),qty:N($('finLineQtyV15')?.value),min_quantity:N($('finLineMinQtyV15')?.value)||1,price:N($('finLinePriceV15')?.value),tax_mode:S($('finLineTaxModeV15')?.value)||'before',unit:S($('finLineUnitV15')?.value)||'حبة',item_type:S($('finLineTypeV15')?.value)||'مادة',image:S(window.__financeProLineImageV15||'')}; const existing=state.items.find(i=>String(i.id)===existingId); if(existing&&!line.name)line.name=S(existing.name); if(!line.name)return alert('اسم المنتج مطلوب'); if(line.qty<=0)return alert('الكمية مطلوبة'); if(line.price<0)return alert('السعر غير صحيح'); if(!line.image&&!(existing&&S(existing.image_url)))return alert('يجب إرفاق صورة للمنتج أو اختيار منتج لديه صورة'); state.invoiceLines.push(line); ['finLineNameV15','finLineDistributorCodeV15','finLineSupplierInvoiceV15','finLineQtyV15','finLineMinQtyV15','finLinePriceV15'].forEach(id=>{if($(id))$(id).value='';}); if($('finExistingProductV15'))$('finExistingProductV15').value=''; if($('finLineCodeV15'))$('finLineCodeV15').value=nextInternalCode(); if($('finLineImageV15'))$('finLineImageV15').value=''; if($('finLineImageNameV15'))$('finLineImageNameV15').textContent='لم يتم اختيار صورة'; window.__financeProLineImageV15=''; renderInvoiceLines();};
