  async function loadInvoiceRows(invoiceNo){const c=client(); if(!c)throw new Error('الاتصال غير جاهز'); invoiceNo=decodeURIComponent(S(invoiceNo)); const res=await c.from('inventory_movements').select('*').eq('movement_type','in').or(`notes.ilike.%${invoiceNo}%,reason.ilike.%${invoiceNo}%`).order('created_at',{ascending:false}).limit(1000); if(res.error)throw res.error; return A(res.data);}
  window.financeProLoadSupplierInvoiceV15=async function(encoded,btn){try{if(btn){btn.disabled=true;btn.textContent='جاري التحميل...';} const invoiceNo=decodeURIComponent(S(encoded||$('finInvNoV15')?.value)); if(!invoiceNo)throw new Error('رقم الفاتورة مطلوب'); const rows=await loadInvoiceRows(invoiceNo); if(!rows.length)return alert('لم يتم العثور على عملية بهذا الرقم'); const first=rows[0], meta0=safeJson(first.notes)||{}; state.tab='add'; state.invoiceLines=rows.map(m=>{const meta=safeJson(m.notes)||{}, q=N(m.quantity), mode=S(meta.taxMode||'before'), price=mode==='after'&&q>0?N(meta.afterVat)/q:N(m.unit_cost); return {existing_item_id:m.item_id,name:S(m.item_name),code:S(m.product_code),distributor_code:S(m.barcode),supplier_invoice_no:S(meta.supplierInvoiceNo),qty:q,min_quantity:N(meta.minQuantity)||1,price,tax_mode:mode,unit:'حبة',item_type:'مادة',image:''};}); renderShell(); if($('finInvSupplierV15'))$('finInvSupplierV15').value=S(meta0.supplier||first.receiver||''); if($('finInvNoV15'))$('finInvNoV15').value=invoiceNo; if($('finInvDateV15'))$('finInvDateV15').value=S(first.movement_date||first.created_at).slice(0,10)||today(); renderInvoiceLines(); if(typeof msg==='function')msg('تم تحميل العملية للتعديل/المراجعة بسرعة');}catch(e){alert(e.message||String(e));}finally{if(btn){btn.disabled=false;btn.textContent='تحميل العملية';}}};
  window.financeProDeleteSupplierInvoiceV15=async function(encoded,btn){try{const invoiceNo=decodeURIComponent(S(encoded||$('finInvNoV15')?.value)); if(!invoiceNo)throw new Error('رقم الفاتورة مطلوب'); if(!confirm('حذف فاتورة المورد رقم '+invoiceNo+'؟ سيتم حذف حركات الإدخال وعكس أثرها على الكمية فقط.'))return; if(btn){btn.disabled=true;btn.textContent='جاري الحذف...';} const c=client(); if(!c)throw new Error('الاتصال غير جاهز'); let usedRpc=false, rows=[]; try{const rpc=await c.rpc('tasneef_delete_supplier_invoice_v10088',{p_invoice_no:invoiceNo}); if(rpc.error)throw rpc.error; usedRpc=true;}catch(_){rows=await loadInvoiceRows(invoiceNo); if(!rows.length)throw new Error('لم يتم العثور على حركات لهذه الفاتورة'); for(const m of rows){const it=state.items.find(i=>String(i.id)===String(m.item_id)); if(it){const next=N(it.quantity)-N(m.quantity); const upd=await c.from('inventory_items').update({quantity:next}).eq('id',it.id); if(upd.error)throw upd.error;}} const ids=rows.map(r=>r.id).filter(Boolean); const del=await c.from('inventory_movements').delete().in('id',ids); if(del.error)throw del.error;} state.movements=state.movements.filter(m=>!S(m.notes).includes(invoiceNo)&&!S(m.reason).includes(invoiceNo)); state.invoiceLines=[]; await loadAll(true); renderShell(); alert(usedRpc?'تم حذف الفاتورة وتحديث الكميات':'تم حذف الفاتورة وتحديث الكميات.');}catch(e){alert(e.message||String(e));}finally{if(btn){btn.disabled=false;btn.textContent='حذف الفاتورة';}}};
  window.financeProShowInvoiceV15=function(encoded){const invoiceNo=decodeURIComponent(encoded); const inv=invoicesFromMovements().find(x=>S(x.invoiceNo)===S(invoiceNo)); if(!inv)return; const rows=inv.lines.map(m=>`<tr><td>${esc(m.item_name)}</td><td>${esc(m.product_code||'-')}</td><td>${N(m.quantity)}</td><td>${money(movementUnitCost(m))}</td><td>${money(movementNet(m))}</td><td>${money(movementVat(m))}</td><td>${money(movementGross(m))}</td></tr>`).join(''); modal('فاتورة مخزون: '+invoiceNo,`<div class="fin-grid three"><div class="fin-card"><h3>المورد</h3><b>${esc(inv.supplier||'-')}</b></div><div class="fin-card"><h3>التاريخ</h3><b>${esc(inv.date||'-')}</b></div><div class="fin-card"><h3>عدد المنتجات</h3><b>${inv.lines.length}</b></div></div><div class="fin-table"><table><thead><tr><th>المنتج</th><th>الكود</th><th>الكمية</th><th>سعر الوحدة</th><th>قبل الضريبة</th><th>الضريبة</th><th>بعد الضريبة</th></tr></thead><tbody>${rows}</tbody></table></div>`);};
  function staffName(id){const u=state.users.find(u=>String(u.id)===String(id)); return u?S(u.full_name||u.name||u.username):'';} function projectName(id){const p=state.projects.find(p=>String(p.id)===String(id)); return p?S(p.name||p.project_name):'';}
  function renderMovement(body){const rows=state.movements.slice().reverse().slice(0,80); const items=state.items.filter(i=>computedItemQty(i)>0||isWarehouseOnly()); body.innerHTML=`<div class="fin-card"><h3>صرف منتج وتوزيع استهلاكه</h3><div class="fin-grid three"><div><label>المنتج</label><select id="finMoveItemV15">${items.map(i=>`<option value="${esc(i.id)}">${esc(i.name)} - المتوفر ${N(computedItemQty(i))}</option>`).join('')}</select></div><div><label>نوع الحركة</label><select id="finMoveTypeV15"><option value="out">صرف</option><option value="consume">مستهلك</option><option value="waste">مهدور</option><option value="damaged">تالف</option><option value="scrap">سكراب</option><option value="return">مرتجع</option></select></div><div><label>المستلم</label><select id="finMoveStaffV15">${state.users.map(u=>`<option value="${esc(u.id)}">${esc(u.full_name||u.name||u.username)} - ${esc(u.role||'')}</option>`).join('')}</select></div><div><label>الكمية</label><input id="finMoveQtyV15" type="number" min="0" step="0.01"></div><div><label>التاريخ</label><input id="finMoveDateV15" type="date" value="${today()}"></div><div><label>ملاحظة</label><input id="finMoveNoteV15"></div></div><div class="fin-actions"><button onclick="financeProSaveMovementV15(this)">حفظ الحركة</button></div></div><div class="fin-card"><h3>حركات المخزون</h3><div class="fin-table"><table><thead><tr><th>التاريخ</th><th>النوع</th><th>المنتج</th><th>الكمية</th><th>المستلم</th><th>إجراء</th></tr></thead><tbody>${rows.map(m=>`<tr><td>${esc(S(m.movement_date||m.created_at).slice(0,10))}</td><td>${esc(movementTypeLabel(m.movement_type))}</td><td>${esc(m.item_name||'')}</td><td>${N(m.quantity)}</td><td>${esc(m.receiver||'')}</td><td class="fin-actions"><button class="light" onclick="financeProShowMovementV15(${Number(m.id)||0})">عرض</button><button class="danger" onclick="financeProDeleteMovementV15(${Number(m.id)||0})">حذف</button></td></tr>`).join('')||'<tr><td colspan="6">لا توجد حركات</td></tr>'}</tbody></table></div></div>`;}
  window.financeProSaveMovementV15=async function(btn){try{if(btn)btn.disabled=true; const c=client(); if(!c)throw new Error('الاتصال غير جاهز'); const item=state.items.find(i=>String(i.id)===String($('finMoveItemV15')?.value)); if(!item)throw new Error('اختر المنتج'); const qty=N($('finMoveQtyV15')?.value), type=S($('finMoveTypeV15')?.value)||'out'; if(qty<=0)throw new Error('الكمية مطلوبة'); if(['out','consume','waste','damaged','scrap'].includes(type)&&computedItemQty(item)<qty)throw new Error('الكمية المتوفرة لا تكفي'); const staff=S($('finMoveStaffV15')?.value), date=S($('finMoveDateV15')?.value)||today(); const mv={item_id:item.id,item_name:item.name,movement_type:type,quantity:qty,movement_date:date,receiver:staffName(staff),reason:{return:'مرتجع مخزون',consume:'مستهلك',waste:'مهدور',damaged:'تالف',scrap:'سكراب',out:'صرف مخزون'}[type]||'صرف مخزون',notes:'finance_pro_v15:'+JSON.stringify({module:VERSION,staffId:staff,note:S($('finMoveNoteV15')?.value)}),product_code:itemCode(item),barcode:itemCode(item),unit_cost:+itemUnitCost(item).toFixed(4)}; const res=await c.from('inventory_movements').insert(mv); if(res.error)throw res.error; const next=N(item.quantity)+(type==='return'?qty:-qty); const upd=await c.from('inventory_items').update({quantity:next}).eq('id',item.id); if(upd.error)throw upd.error; await loadAll(true); renderShell();}catch(e){alert(e.message||String(e));}finally{if(btn)btn.disabled=false;}};
  window.financeProDeleteMovementV15=async function(id){try{const m=state.movements.find(x=>Number(x.id)===Number(id)); if(!m)return; if(!confirm('حذف حركة المخزون؟ سيتم عكس أثرها على رصيد المنتج.'))return; const c=client(); const item=state.items.find(i=>String(i.id)===String(m.item_id)); if(item){const next=N(item.quantity)-movementStockDelta(m); const upd=await c.from('inventory_items').update({quantity:next}).eq('id',item.id); if(upd.error)throw upd.error;} const res=await c.from('inventory_movements').delete().eq('id',id); if(res.error)throw res.error; await loadAll(true); renderShell();}catch(e){alert(e.message||String(e));}};
  window.financeProShowMovementV15=id=>{const m=state.movements.find(x=>Number(x.id)===Number(id)); if(!m)return; modal('تفاصيل حركة المخزون',`<div class="fin-grid three"><div class="fin-card"><h3>المنتج</h3><b>${esc(m.item_name)}</b></div><div class="fin-card"><h3>نوع الحركة</h3><b>${esc(movementTypeLabel(m.movement_type))}</b></div><div class="fin-card"><h3>الكمية</h3><b>${N(m.quantity)}</b></div><div class="fin-card"><h3>المستلم</h3><b>${esc(m.receiver||'-')}</b></div><div class="fin-card"><h3>التاريخ</h3><b>${esc(S(m.movement_date||m.created_at).slice(0,10))}</b></div></div><div class="fin-soft">${esc(m.reason||'')}</div>`);};
  window.financeProShowProductV15=id=>{const item=state.items.find(i=>String(i.id)===String(id)); if(!item)return; const moves=productMovements(item), ins=moves.filter(m=>S(m.movement_type)==='in'), outs=moves.filter(m=>['out','consume','waste','damaged','scrap'].includes(S(m.movement_type))), returns=moves.filter(m=>S(m.movement_type)==='return'); const rows=arr=>arr.map(m=>`<tr><td>${esc(S(m.movement_date||m.created_at).slice(0,10))}</td><td>${esc(movementTypeLabel(m.movement_type))}</td><td>${N(m.quantity)}</td><td>${esc(m.receiver||'-')}</td><td>${money(movementNet(m))}</td></tr>`).join('')||'<tr><td colspan="5">لا توجد بيانات</td></tr>'; modal('بيانات المنتج: '+S(item.name),`${item.image_url?`<img src="${esc(item.image_url)}" style="width:96px;height:96px;object-fit:contain;border:1px solid #d9e7e2;border-radius:16px;background:#fff;padding:4px">`:''}<div class="fin-grid"><div class="fin-card fin-kpi"><small>الداخل</small><b>${ins.reduce((a,m)=>a+N(m.quantity),0)}</b></div><div class="fin-card fin-kpi"><small>الخارج</small><b>${outs.reduce((a,m)=>a+N(m.quantity),0)}</b></div><div class="fin-card fin-kpi"><small>المرتجع</small><b>${returns.reduce((a,m)=>a+N(m.quantity),0)}</b></div><div class="fin-card fin-kpi"><small>الرصيد الحالي</small><b>${N(item.quantity)}</b></div></div><h3>الداخل</h3><div class="fin-table"><table><thead><tr><th>التاريخ</th><th>النوع</th><th>الكمية</th><th>المورد</th><th>القيمة</th></tr></thead><tbody>${rows(ins)}</tbody></table></div><h3>الخارج</h3><div class="fin-table"><table><thead><tr><th>التاريخ</th><th>النوع</th><th>الكمية</th><th>المستلم</th><th>القيمة</th></tr></thead><tbody>${rows(outs)}</tbody></table></div>`);};
