  function renderCostCenter(body){body.innerHTML=`<div class="fin-card"><h3>مركز التكلفة</h3><p class="fin-soft">تسجيل المصروفات الإدارية ومراجعة التكاليف.</p><div class="fin-grid three"><div><label>قبل الضريبة</label><input id="finCostNetV15" type="number" oninput="financeProCalcExpenseV15()"></div><div><label>الضريبة</label><input id="finCostVatV15" readonly></div><div><label>بعد الضريبة</label><input id="finCostGrossV15" readonly></div></div></div>`;}
  window.financeProCalcExpenseV15=function(){const net=N($('finCostNetV15')?.value); if($('finCostVatV15'))$('finCostVatV15').value=(net*VAT).toFixed(2); if($('finCostGrossV15'))$('finCostGrossV15').value=(net*(1+VAT)).toFixed(2);};
  function renderReports(body){const stock=stockValue(); body.innerHTML=`<div class="fin-card"><h3>التقارير</h3><div class="fin-soft">هذه النسخة تعرض جرد المخزون الحالي، والمنتجات ذات الرصيد صفر لا تظهر.</div><div class="fin-table"><table><thead><tr><th>المنتج</th><th>الكود</th><th>الوحدة</th><th>النوع</th><th>الرصيد</th><th>قبل الضريبة</th><th>الضريبة</th><th>بعد الضريبة</th></tr></thead><tbody>${state.items.filter(i=>computedItemQty(i)>0).map(i=>{const net=computedItemQty(i)*itemUnitCost(i); return `<tr><td>${esc(i.name)}</td><td>${esc(itemCode(i))}</td><td>${esc(i.unit||'-')}</td><td>${esc(productType(i))}</td><td>${N(computedItemQty(i))}</td><td>${money(net)}</td><td>${money(net*VAT)}</td><td>${money(net*(1+VAT))}</td></tr>`;}).join('')||'<tr><td colspan="8">لا توجد منتجات برصيد متاح</td></tr>'}</tbody></table></div><div class="fin-grid three" style="margin-top:12px"><div class="fin-card fin-kpi"><small>الإجمالي قبل الضريبة</small><b>${money(stock)}</b></div><div class="fin-card fin-kpi"><small>الضريبة</small><b>${money(stock*VAT)}</b></div><div class="fin-card fin-kpi"><small>الإجمالي بعد الضريبة</small><b>${money(stock*(1+VAT))}</b></div></div></div>`;}
  function modal(title,html){document.body.insertAdjacentHTML('beforeend',`<div class="modal-backdrop" onclick="if(event.target===this)this.remove()" style="position:fixed;inset:0;background:rgba(0,35,28,.45);z-index:99999;display:grid;place-items:center;padding:18px"><div class="card" style="width:min(1120px,96vw);max-height:92vh;overflow:auto"><div class="fin-actions" style="justify-content:space-between"><h2>${esc(title)}</h2><button class="danger" onclick="this.closest('.modal-backdrop').remove()">إغلاق</button></div>${html}</div></div>`);}
