  function patchShowPage(){if(window.__financeProShowPagePatchedV10088)return; window.__financeProShowPagePatchedV10088=true; const old=window.showPage; window.showPage=function(id,btn){if(id==='financeDashboard'){ensurePage(); document.querySelectorAll('.page').forEach(p=>p.classList.add('hidden')); $('financeDashboard')?.classList.remove('hidden'); document.querySelectorAll('.nav').forEach(n=>n.classList.remove('active')); btn?.classList.add('active'); loadAll(false).then(renderShell); return;} return typeof old==='function'?old.apply(this,arguments):undefined;}; try{showPage=window.showPage;}catch(_){}}
